import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"騎砍2 | 終極跑商路線圖：從行商到商業帝國","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/trade-routes.md","filePath":"bannerlord/trade-routes.md"}'),n={name:"bannerlord/trade-routes.md"};function o(i,a,s,h,d,c){return e(),r("div",null,[...a[0]||(a[0]=[l(`<h1 id="騎砍2-終極跑商路線圖-從行商到商業帝國" tabindex="-1">騎砍2 | 終極跑商路線圖：從行商到商業帝國 <a class="header-anchor" href="#騎砍2-終極跑商路線圖-從行商到商業帝國" aria-label="Permalink to &quot;騎砍2 | 終極跑商路線圖：從行商到商業帝國&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>在卡拉迪亞，打仗很帥，但跑商穩定。一條好路線跑順了，日入上萬不是問題，而且<strong>零風險</strong>——不用怕兵死光、不用怕被俘虜。</p><hr><h2 id="一、跑商基礎" tabindex="-1">一、跑商基礎 <a class="header-anchor" href="#一、跑商基礎" aria-label="Permalink to &quot;一、跑商基礎&quot;">​</a></h2><h3 id="_1-1-物價怎麼看" tabindex="-1">1.1 物價怎麼看 <a class="header-anchor" href="#_1-1-物價怎麼看" aria-label="Permalink to &quot;1.1 物價怎麼看&quot;">​</a></h3><p>滑鼠移到商品上 → <strong>綠色</strong> = 比均價便宜 → 買進。<strong>紅色</strong> = 比均價貴 → 賣出。</p><h3 id="_1-2-影響物價的因素" tabindex="-1">1.2 影響物價的因素 <a class="header-anchor" href="#_1-2-影響物價的因素" aria-label="Permalink to &quot;1.2 影響物價的因素&quot;">​</a></h3><ul><li>城鎮周圍村莊生產什麼 → 原料便宜</li><li>城鎮缺什麼 → 需求品貴</li><li>商隊來往頻率 → 頻繁進出會拉平物價</li><li>戰爭狀態 → 被圍城/掠奪過的城物價飆漲</li></ul><h3 id="_1-3-必備裝備" tabindex="-1">1.3 必備裝備 <a class="header-anchor" href="#_1-3-必備裝備" aria-label="Permalink to &quot;1.3 必備裝備&quot;">​</a></h3><ul><li><strong>騾子/駱駝 5-8 頭</strong>：增加負重，太多拖慢移速</li><li><strong>交易 perk</strong>：批發商（降低貿易懲罰）、市場經紀人（自動更新物價）</li></ul><hr><h2 id="二、金幣路線" tabindex="-1">二、金幣路線 <a class="header-anchor" href="#二、金幣路線" aria-label="Permalink to &quot;二、金幣路線&quot;">​</a></h2><h3 id="🥇-穀物線-最穩" tabindex="-1">🥇 穀物線（最穩） <a class="header-anchor" href="#🥇-穀物線-最穩" aria-label="Permalink to &quot;🥇 穀物線（最穩）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>起點</th><th>終點</th><th style="text-align:center;">利潤/趟</th></tr></thead><tbody><tr><td>南帝國村莊（達努斯蒂卡 Danustica 周邊）</td><td>北帝國城鎮</td><td style="text-align:center;">3000-5000</td></tr><tr><td>庫塞特東部村莊（奧多赫 Odokh 周邊）</td><td>帝國城鎮</td><td style="text-align:center;">2000-4000</td></tr></tbody></table><blockquote><p>南帝國達努斯蒂卡周圍村莊盛產穀物：<strong>Menzura、Qasira、Asmait</strong> 等村，穀物價格全大陸最低。</p></blockquote><blockquote><p>穀物永遠有需求，戰爭期間糧食價格翻倍。</p></blockquote><h3 id="🥈-硬木線" tabindex="-1">🥈 硬木線 <a class="header-anchor" href="#🥈-硬木線" aria-label="Permalink to &quot;🥈 硬木線&quot;">​</a></h3><table tabindex="0"><thead><tr><th>起點</th><th>終點</th><th style="text-align:center;">利潤/趟</th></tr></thead><tbody><tr><td>巴坦尼亞村莊</td><td>阿塞萊城鎮</td><td style="text-align:center;">2000-4000</td></tr><tr><td>巴坦尼亞村莊</td><td>斯特吉亞城鎮</td><td style="text-align:center;">1500-3000</td></tr></tbody></table><blockquote><p>🪓 巴坦尼亞森林多，硬木便宜到哭。重點村莊：<strong>Glenlithrig、Tor Leiad、Mag Arba、Ebbseth、Tor Melina</strong> — 這些村子圍繞在 Marunath、Seonon、Dunglanys 周圍，硬木價格常年在 15-30 金。</p></blockquote><h3 id="🥉-牲畜線" tabindex="-1">🥉 牲畜線 <a class="header-anchor" href="#🥉-牲畜線" aria-label="Permalink to &quot;🥉 牲畜線&quot;">​</a></h3><table tabindex="0"><thead><tr><th>起點</th><th>終點</th><th style="text-align:center;">利潤/趟</th></tr></thead><tbody><tr><td>庫塞特東部村莊（Balkhans、Odokh 周邊）</td><td>帝國城鎮</td><td style="text-align:center;">2000-3000</td></tr><tr><td>阿塞萊沙漠村莊（Husn Fulq、Razih 周邊）</td><td>瓦蘭迪亞</td><td style="text-align:center;">2000-3500</td></tr></tbody></table><blockquote><p>牲畜會自己走路（不用負重），但移動速度會變慢。</p></blockquote><h3 id="_4-銀礦-珠寶線" tabindex="-1">4. 銀礦/珠寶線 <a class="header-anchor" href="#_4-銀礦-珠寶線" aria-label="Permalink to &quot;4. 銀礦/珠寶線&quot;">​</a></h3><table tabindex="0"><thead><tr><th>起點</th><th>終點</th><th style="text-align:center;">利潤/趟</th></tr></thead><tbody><tr><td>斯特吉亞銀礦村（Omor、Balgard 周邊）</td><td>帝國/瓦蘭迪亞</td><td style="text-align:center;">3000-6000</td></tr></tbody></table><blockquote><p>斯特吉亞 Omor 和 Balgard 周邊有全大陸唯一的銀礦村莊，珠寶原料產地。</p></blockquote><blockquote><p>利潤最高，但需求量較小，需要等城鎮消化。</p></blockquote><hr><h2 id="三、進階技巧" tabindex="-1">三、進階技巧 <a class="header-anchor" href="#三、進階技巧" aria-label="Permalink to &quot;三、進階技巧&quot;">​</a></h2><h3 id="_3-1-貿易傳聞" tabindex="-1">3.1 貿易傳聞 <a class="header-anchor" href="#_3-1-貿易傳聞" aria-label="Permalink to &quot;3.1 貿易傳聞&quot;">​</a></h3><p>進城 → 點交易 → 看周圍城鎮價格浮動。這功能可以讓你不用親自跑過去就知道哪邊便宜哪邊貴。</p><h3 id="_3-2-戰時發財" tabindex="-1">3.2 戰時發財 <a class="header-anchor" href="#_3-2-戰時發財" aria-label="Permalink to &quot;3.2 戰時發財&quot;">​</a></h3><p>打仗期間：</p><ul><li>被圍城的城鎮糧食價格暴漲 → 運糧食去賣</li><li>被掠奪的村莊原料停產 → 相關商品會漲價</li><li>敵對國城鎮無法貿易 → 中立國城鎮商機大增</li></ul><h3 id="_3-3-工廠聯動" tabindex="-1">3.3 工廠聯動 <a class="header-anchor" href="#_3-3-工廠聯動" aria-label="Permalink to &quot;3.3 工廠聯動&quot;">​</a></h3><p>在跑商路線的起點/終點買工廠，形成閉環：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>起點買原料（便宜）→ 工廠加工 → 終點賣成品（貴）</span></span></code></pre></div><p>例如：在巴坦尼亞買木材廠，原料自己產，成品賣到阿塞萊。</p><hr><h2 id="四、完整跑商環線" tabindex="-1">四、完整跑商環線 <a class="header-anchor" href="#四、完整跑商環線" aria-label="Permalink to &quot;四、完整跑商環線&quot;">​</a></h2><h3 id="推薦環線-一圈約-5-7-天" tabindex="-1">推薦環線（一圈約 5-7 天） <a class="header-anchor" href="#推薦環線-一圈約-5-7-天" aria-label="Permalink to &quot;推薦環線（一圈約 5-7 天）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>南帝國達努斯蒂卡 Danustica（買穀物，村：Menzura、Qasira）</span></span>
<span class="line"><span>  → 北帝國阿爾戈隆 Argoron（賣穀物）</span></span>
<span class="line"><span>  → 巴坦尼亞馬魯納斯 Marunath（買硬木，村：Glenlithrig、Tor Leiad）</span></span>
<span class="line"><span>  → 阿塞萊胡森富爾 Husn Fulq（賣硬木）</span></span>
<span class="line"><span>  → 庫塞特奧多赫 Odokh（買牲畜，村：Balkhans）</span></span>
<span class="line"><span>  → 帝國（賣牲畜）</span></span>
<span class="line"><span>  → 回到起點（重複）</span></span></code></pre></div><blockquote><p>一圈淨利約 8000-15000 金，跑兩圈就能開一間工廠。</p></blockquote><hr><h2 id="結語" tabindex="-1">結語 <a class="header-anchor" href="#結語" aria-label="Permalink to &quot;結語&quot;">​</a></h2><p>跑商的秘訣不是找到一條神路線，而是建立<strong>環線</strong>——讓每一趟都有貨可帶，不空車跑路。</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./money-making.html">騎砍2 | 賺錢密技</a></li><li><a href="./smithing-guide.html">騎砍2 | 鍛造系統深入指南</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>`,55)])])}const b=t(n,[["render",o]]);export{p as __pageData,b as default};
